            // Odd index: Must be a non-prime number
            if (isPrime(num)) {
                const nextNonPrime = findNextNonPrime(num);
                const cost = nextNonPrime - num;
                totalOperations += cost;
            }
            // If it is non-prime, cost is 0.
        }
    }

    return totalOperations;
}

